import {
  outputAndExit,
  successResponse,
  errorResponse,
  fromNeverthrowError,
} from '@/cli/output';

import { detectInstalledClients } from '@/cli/commands/install/detect-clients';
import type {
  AddServerFailure,
  AddServerSuccess,
} from '@/cli/commands/install/2-add-server';
import { tryAddServer } from '@/cli/commands/install/2-add-server';
import { getWalletInfo } from '@/operations/wallet';
import { redeemInviteCode } from '@/shared/redeem-invite';
import { installGitHubSkill } from '@/shared/skills/github';
import { detectAgents } from '@/shared/skills/core/agents';
import { getBaseUrl } from '@/shared/utils';
import { getOnboardingCta } from '@/operations/onboarding-cta';
import { getWallet } from '@/wallet';

import type { Command, GlobalFlags } from '@/types';
import {
  DEMO_PROMPTS,
  formatDemoPromptsBlock,
  formatDemoPromptsJson,
  type DemoPrompt,
} from '../lib/demo-prompts';
import type { BaseError, OkValue } from '@agentcash/neverthrow/types';
import chalk from 'chalk';

const SURFACE = 'cli:onboard';
const AGENTCASH_SKILL = {
  owner: 'merit-systems',
  repo: 'agentcash-skills',
  skillPath: 'skills/agentcash',
};

const formatClientList = (clients: string[]) =>
  clients.length > 0 ? clients.join(', ') : 'none detected';

const formatMcpFailures = (failures: AddServerFailure[]) =>
  failures.map(failure => `${failure.name} (${failure.message})`);

const formatSuccessOutput = (params: {
  dev: boolean;
  skillMd: string;
  installedAgents: string[];
  mcpResult: Awaited<ReturnType<typeof installDetectedMcpServers>>;
  balance: number;
  redeem?: OkValue<Awaited<ReturnType<typeof redeemInviteCode>>>;
  prompts: DemoPrompt[];
  connectedProviders?: { platform: string; username: string }[];
  email?: string;
}) => {
  const lines = ['agentcash onboarding complete!'];

  if (params.redeem) {
    lines.push(
      `You've successfully redeemed $${params.redeem.amount.toFixed(2)}!`
    );
  }

  lines.push(
    formatDemoPromptsBlock(getBaseUrl(params.dev), params.prompts, {
      connectedProviders: params.connectedProviders,
      email: params.email,
    })
  );
  lines.push('', params.skillMd.trimEnd());

  return lines.join('\n');
};

const formatRedeemFailureOutput = (params: {
  args: GlobalFlags;
  installedAgents: string[];
  mcpResult: Awaited<ReturnType<typeof installDetectedMcpServers>>;
  redeemError: BaseError;
}) => {
  const onboardingLink = `${getBaseUrl(params.args.dev)}/onboard`;
  const lines = [
    'agentcash setup finished, but invite redemption failed.',
    `Reason: ${params.redeemError.message}`,
    `Finish onboarding at: ${onboardingLink}`,
    `Skill installed for: ${formatClientList(params.installedAgents)}`,
    `MCP configured for: ${formatClientList(params.mcpResult.installed.map(result => result.name))}`,
  ];

  const mcpFailures = formatMcpFailures(params.mcpResult.failed);
  if (mcpFailures.length > 0) {
    lines.push(`MCP not configured for: ${mcpFailures.join(', ')}`);
  }

  return lines.join('\n');
};

function progress(flags: GlobalFlags, message: string): void {
  if (flags.quiet) return;
  process.stderr.write(chalk.dim(message) + '\n');
}

function installAgentcashWalletSkill() {
  return installGitHubSkill(SURFACE, AGENTCASH_SKILL);
}

async function installDetectedMcpServers(args: GlobalFlags) {
  const installed: AddServerSuccess[] = [];
  const failed: AddServerFailure[] = [];

  for (const client of detectInstalledClients()) {
    const result = await tryAddServer(
      client,
      { ...args, yes: true },
      { silent: true }
    );

    if (result.success) {
      installed.push(result.value);
      continue;
    }

    failed.push(result.error);
  }

  return {
    failed,
    installed,
  };
}

export const onboardCommand: Command<{
  code?: string;
}> = async args => {
  const walletResult = await getWallet();

  if (walletResult.isErr()) {
    return outputAndExit(
      fromNeverthrowError(walletResult, 'WALLET_ERROR'),
      args
    );
  }

  progress(args, 'Installing agentcash wallet skill...');
  const skillInstallResult = await installAgentcashWalletSkill();

  if (skillInstallResult.isErr()) {
    return outputAndExit(
      errorResponse({
        code: 'GENERAL_ERROR',
        message: skillInstallResult.error.message,
        surface: SURFACE,
        cause: 'skill_install_failed',
      }),
      args
    );
  }

  const skillInstall = skillInstallResult.value;

  progress(args, 'Configuring MCP for detected clients...');
  const mcpResult = await installDetectedMcpServers(args);
  const installedAgents = detectAgents().map(agent => agent.name);

  // Redeem invite code if provided
  let redeemValue;

  if (args.code) {
    progress(args, 'Redeeming invite code...');
    const redeemResult = await redeemInviteCode(
      SURFACE,
      { code: args.code },
      args,
      walletResult.value
    );

    if (redeemResult.isErr()) {
      // Code was provided but failed — always error

      return outputAndExit(
        successResponse(
          args.format === 'pretty'
            ? formatRedeemFailureOutput({
                args,
                installedAgents,
                mcpResult,
                redeemError: redeemResult.error,
              })
            : {
                message:
                  'agentcash setup finished, but invite redemption failed. Finish onboarding on agentcash.dev.',
                redeemed: false,
                onboardingLink: `${getBaseUrl(args.dev)}/onboard`,
                redeemError: {
                  cause: redeemResult.error.cause,
                  message: redeemResult.error.message,
                },
                skill: {
                  installedAgents,
                  path: skillInstall.installResult.path,
                },
                mcp: mcpResult,
              }
        ),
        args
      );
    }

    redeemValue = redeemResult.value;
  }

  // Fetch balance — needed both for display and to gate no-code onboarding
  progress(args, 'Fetching wallet balance...');
  const walletInfo = await getWalletInfo(SURFACE, walletResult.value, args);

  // No code and zero balance — can't continue
  if (!args.code && walletInfo.totalBalance <= 0) {
    const cta = getOnboardingCta(args);
    return outputAndExit(
      errorResponse({
        code: 'GENERAL_ERROR',
        message: cta.message,
        surface: SURFACE,
        cause: 'no_funds',
      }),
      args
    );
  }

  const prompts = redeemValue?.prompts ?? DEMO_PROMPTS;

  return outputAndExit(
    successResponse(
      args.format === 'pretty'
        ? formatSuccessOutput({
            dev: args.dev,
            installedAgents,
            mcpResult,
            redeem: redeemValue,
            skillMd: skillInstall.skillMd,
            prompts,
            balance: walletInfo.totalBalance,
            connectedProviders: redeemValue?.connectedProviders,
            email: redeemValue?.email,
          })
        : {
            message: 'agentcash onboarding complete',
            redeemed: !!redeemValue,
            ...(redeemValue
              ? {
                  invite: {
                    amount: redeemValue.amount,
                    txHash: redeemValue.txHash,
                  },
                }
              : {}),
            wallet: walletInfo,
            skill: {
              installedAgents,
              installedPaths: [skillInstall.installResult.path],
              linkedAgents: skillInstall.installResult.agents,
              name: 'agentcash',
              skillMd: skillInstall.skillMd,
            },
            mcp: mcpResult,
            ...formatDemoPromptsJson(getBaseUrl(args.dev), prompts, {
              connectedProviders: redeemValue?.connectedProviders,
              email: redeemValue?.email,
            }),
          }
    ),
    args
  );
};
