import fs from 'fs';
import os from 'os';
import path from 'path';
import process from 'process';

import { getPlatformPath } from './2-add-server/lib';
import { detectAgents as detectAgents } from '@/shared/skills/core/agents';

import { Clients } from './clients';

const agentClientMap: Partial<Record<string, Clients>> = {
  'Claude Code': Clients.ClaudeCode,
  Cline: Clients.Cline,
  Codex: Clients.Codex,
  Cursor: Clients.Cursor,
  'Gemini CLI': Clients.GeminiCli,
  Goose: Clients.Goose,
  OpenCode: Clients.OpenCode,
  Windsurf: Clients.Windsurf,
};

export function detectInstalledClients(): Clients[] {
  const clients = new Set<Clients>();
  const homeDir = os.homedir();
  const { baseDir } = getPlatformPath();

  for (const agent of detectAgents()) {
    const client = agentClientMap[agent.name];
    if (client) {
      clients.add(client);
    }
  }

  if (fs.existsSync(path.join(homeDir, '.claude.json'))) {
    clients.add(Clients.ClaudeCode);
  }

  if (fs.existsSync(path.join(baseDir, 'Claude'))) {
    clients.add(Clients.Claude);
  }

  const zedPath =
    process.platform === 'win32'
      ? path.join(
          process.env.APPDATA ?? path.join(homeDir, 'AppData', 'Roaming'),
          'Zed'
        )
      : path.join(homeDir, '.config', 'zed');

  if (fs.existsSync(zedPath)) {
    clients.add(Clients.Zed);
  }

  return [...clients];
}
